import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import axios from 'axios';

// इम्पोर्ट्स
import Navbar from './components/Navbar';
import Marketplace from './pages/Marketplace';
import Contact from './pages/Contact';
import Scanner from './pages/Scanner';
import Signup from './pages/Signup'; // १. नवीन Signup पेज इम्पोर्ट केले

function App() {
  const [jobs, setJobs] = useState([]);

  useEffect(() => {
    // बॅकएंडवरून जॉब्स आणणे
    axios.get('http://localhost:5000/api/jobs')
      .then(res => setJobs(res.data))
      .catch(err => console.error("Backend Error:", err));
  }, []);

  return (
    <Router>
      <div className="min-h-screen">
        {/* नेव्हबार नेहमी वर राहील */}
        <Navbar />

        <Routes>
          {/* १. होम पेज (Dashboard Look) */}
          <Route path="/" element={
            <div className="flex">
              {/* Sidebar */}
              <div className="w-64 bg-slate-900 text-white p-6 shadow-xl min-h-screen">
                <h2 className="text-2xl font-bold text-blue-400 mb-10">FreelanceHub</h2>
                <nav className="space-y-4">
                  <a href="#" className="block p-3 bg-blue-600 rounded">Dashboard</a>
                  <a href="#" className="block p-3 hover:bg-slate-700 transition">Find Jobs</a>
                </nav>
              </div>

              {/* Main Content Area */}
              <div className="flex-1 p-10 bg-gray-100 min-h-screen">
                <header className="flex justify-between items-center mb-10">
                  <h1 className="text-3xl font-bold text-gray-800">Available Projects</h1>
                  <button className="bg-green-500 text-white px-6 py-2 rounded-full font-semibold shadow-lg hover:bg-green-600 transition">
                    Post a Job
                  </button>
                </header>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {jobs.length > 0 ? jobs.map(job => (
                    <div key={job._id} className="bg-white p-6 rounded-xl shadow-md border-t-4 border-blue-500 hover:shadow-lg transition">
                      <h3 className="text-xl font-bold text-gray-800">{job.title}</h3>
                      <p className="text-blue-600 font-semibold mt-2">{job.budget}</p>
                      <button className="w-full mt-6 bg-slate-800 text-white py-2 rounded-lg hover:bg-black transition">
                        Bid Now
                      </button>
                    </div>
                  )) : (
                    <div className="p-10 bg-white rounded-xl shadow text-center col-span-2">
                      <p className="text-gray-500">No jobs available. Please start your Backend server.</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          } />

          {/* २. इतर सर्व पेजेसचे राऊट्स */}
          <Route path="/marketplace" element={<Marketplace />} />
          <Route path="/contact" element={<Contact />} />
          <Route path="/scanner" element={<Scanner />} />
          <Route path="/signup" element={<Signup />} /> {/* ३. हा नवीन राऊट जोडला आहे */}
          
          <Route path="/login" element={<div className="p-40 text-center text-white text-2xl">Login Page Coming Soon...</div>} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
